import React, { FC } from 'react';
import { Dimensions } from 'react-native';
import { BackDropBottom, Text, Button } from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';

interface PointsInfoBottomSheetProps {
  modalizeRef: React.RefObject<PropsModalizeRef>;
}

const PointsInfoBottomSheet: FC<PointsInfoBottomSheetProps> = ({ modalizeRef }) => {
  const { height } = Dimensions.get('window');

  return (
    <BackDropBottom modalHeight={height * 0.30} modalizeRef={modalizeRef}>
      <Text
        type="paragraphMD"
        align="center"
        color="INTENSE_COLOR_05"
        mt="small"
        mb="smaller"
      >
        Os seus pontos ganhos ficam disponíveis no saldo sempre que você pagar
        sua próxima fatura.
      </Text>

      <Button text="Entendi" onPress={() => modalizeRef.current?.close?.()} />
    </BackDropBottom>
  );
};

export default PointsInfoBottomSheet;

